import pandas as pd

df = pd.DataFrame({
    'first': ['Alice', 'Bob', 'Charlie'],
    'last': ['Smith', 'Jones', 'Brown'],
    'age': [25, 17, 30]
})

exercises.solutionCode:
def process_row(row):
    return {'full_name': row['first'] + ' ' + row['last'], 'is_adult': row['age'] >= 18}

result = df.apply(process_row, axis=1, result_type='expand')
print(result)

