import pandas as pd

df = pd.DataFrame({
    'name': ['Alice', 'Bob', 'Charlie', 'David'],
    'score': [80, 90, 70, 100]
})

exercises.solutionCode:
def add_total(df):
    return df.assign(total=df['math'] + df['english'])

def add_grade(df):
    return df.assign(grade=np.where(df['total'] >= 170, 'A', 'B'))

result = df.pipe(add_total).pipe(add_grade)
print(result)

